} catch(e) {
  throw new Error('Ошибка разбора ответа GPT: ' + e.message);
}

const rooms = parsed.rooms || [];
const shots = parsed.shots || [];

const shotsStatus = {};
shots.forEach(s => { shotsStatus[s.shot_id] = 'pending'; });

const firstShot = shots[0];
if (!firstShot) throw new Error('GPT не вернул точки съёмки');
shotsStatus[firstShot.shot_id] = 'requested';

// HTML-escape dynamic content from LLM to avoid Telegram parse errors
