  return String(s || '').replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;');
}

const roomsList = rooms.map(r => '• ' + h(r.name)).join('\n');
const roomsText = '<b>План проанализирован!</b>\nОбнаруженные помещения:\n' + roomsList
  + '\nВсего точек съёмки: ' + shots.length;

