var chatId = $('Code - Prepare RAG Query').item.json.chatId;
var ragContext = $('Code - Format RAG Results').item.json.ragContext || '';
var session = $('Supabase - Get Analysis Session').item.json;
var planUrl = session.plan_url || '';
var shotsJson = session.shots_json || [];
var shotsStatus = session.shots_status || {};

var SUPABASE_STORAGE = 'https://phnjdyuwtsqqteyqetgm.supabase.co/storage/v1/object/public/bti-files/photos/';

// Build photo URLs for received shots (preserving order from shots_json)
var photoItems = [];
for (var i = 0; i < shotsJson.length; i++) {
  var shot = shotsJson[i];
  var shotId = shot.shot_id || shot.id || '';
  var status = shotsStatus[shotId] || '';
  if (status === 'received' && shotId) {
    photoItems.push(SUPABASE_STORAGE + chatId + '/' + shotId + '.jpg');
  }
}

var systemPrompt = 'Ты - эксперт по проверке перепланировок квартир в России. '+ 'Анализируй план БТИ и фотографии, определяй отклонения от плана. '+ 'Отвечай только на русском языке. '+ 'Всегда возвращай ответ строго в формате JSON без markdown-обертки.';

var userText = 'НОРМАТИВЫ ИЗ БАЗЫ ЗНАНИЙ:\n' + ragContext + '\n\n---\n\n'+ 'Задание: Проанализируй план БТИ (первое изображение) и фотографии комнат.\n\n'+ 'Определи наличие перепланировок, которые отличаются от плана БТИ.\n'+ 'Классифицируй каждое изменение по нормативам.\n\n'+ 'Верни JSON строго в формате:\n'+ '{"confidence": <0-1>, "changes": [{"room_id": "...", "type": "...", "description": "...", "classification": "legal|requires_approval|illegal", "recommendation": "..."}], "summary": "..."}\n\n'+ 'Классификации: legal - изменений нет или разрешено, requires_approval - требует согласования, illegal - незаконно (несущие стены, мокрые зоны, газ).\n'+ 'Если перепланировок нет - верни пустой массив changes, confidence близкий к 1.';

var contentArray = [{ type: 'text', text: userText }];
if (planUrl) {
  contentArray.push({ type: 'image_url', image_url: { url: planUrl, detail: 'high' } });
}
for (var j = 0; j < photoItems.length; j++) {
  contentArray.push({ type: 'image_url', image_url: { url: photoItems[j], detail: 'high' } });
}

var body = {
  model: 'gpt-4o',
  messages: [
    { role: 'system', content: systemPrompt },
    { role: 'user', content: contentArray }
  ],
  max_tokens: 2000,
  response_format: { type: 'json_object' }
};

return [{ json: { chatId: chatId, body: JSON.stringify(body), photoCount: photoItems.length } }];

